import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import com.google.gson.stream.JsonReader;

public class JsonReaderTest {
    private JsonReader jsonReader;
    private Reader mockReader;

    @BeforeEach
    public void setUp() {
        mockReader = mock(Reader.class);
        jsonReader = new JsonReader(mockReader);
    }

    @Test
    public void testConsumeNonExecutePrefix_notEnoughBufferAndFillBufferReturnsFalse() throws Throwable {
        setPos(0);
        setLimit(4);
        setBuffer(new char[1024]);
        // Spy on jsonReader to override fillBuffer and nextNonWhitespace
        JsonReader spyReader = spy(jsonReader);
        doNothing().when(spyReader).nextNonWhitespace(true);
        setPos(spyReader, 0);
        doReturn(false).when(spyReader).fillBuffer(5);

        invokeConsumeNonExecutePrefix(spyReader);

        // pos should be decremented by 1 after nextNonWhitespace(true)
        assertEquals(-1, getPos(spyReader));
    }

    @Test
    public void testConsumeNonExecutePrefix_bufferDoesNotMatchToken() throws Throwable {
        setPos(0);
        setLimit(10);
        char[] buf = new char[1024];
        buf[0] = 'x';
        buf[1] = ']';
        buf[2] = '}';
        buf[3] = '\'';
        buf[4] = '\n';
        setBuffer(buf);
        JsonReader spyReader = spy(jsonReader);
        doNothing().when(spyReader).nextNonWhitespace(true);
        setPos(spyReader, 0);
        doReturn(true).when(spyReader).fillBuffer(5);

        invokeConsumeNonExecutePrefix(spyReader);

        // pos should be decremented by 1 and not advanced by 5
        assertEquals(-1, getPos(spyReader));
    }

    @Test
    public void testConsumeNonExecutePrefix_bufferMatchesToken() throws Throwable {
        setPos(0);
        setLimit(10);
        char[] buf = new char[1024];
        buf[0] = ')';
        buf[1] = ']';
        buf[2] = '}';
        buf[3] = '\'';
        buf[4] = '\n';
        setBuffer(buf);
        JsonReader spyReader = spy(jsonReader);
        doNothing().when(spyReader).nextNonWhitespace(true);
        setPos(spyReader, 0);
        doReturn(true).when(spyReader).fillBuffer(5);

        invokeConsumeNonExecutePrefix(spyReader);

        // pos should be decremented by 1 then incremented by 5
        // net pos = 0 - 1 + 5 = 4
        assertEquals(4, getPos(spyReader));
    }

    // Helper methods to access private fields and methods

    private void setPos(int value) {
        try {
            var field = JsonReader.class.getDeclaredField("pos");
            field.setAccessible(true);
            field.setInt(jsonReader, value);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private int getPos(JsonReader instance) {
        try {
            var field = JsonReader.class.getDeclaredField("pos");
            field.setAccessible(true);
            return field.getInt(instance);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private void setPos(JsonReader instance, int value) {
        try {
            var field = JsonReader.class.getDeclaredField("pos");
            field.setAccessible(true);
            field.setInt(instance, value);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private void setLimit(int value) {
        try {
            var field = JsonReader.class.getDeclaredField("limit");
            field.setAccessible(true);
            field.setInt(jsonReader, value);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private void setBuffer(char[] buf) {
        try {
            var field = JsonReader.class.getDeclaredField("buffer");
            field.setAccessible(true);
            field.set(jsonReader, buf);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private void invokeConsumeNonExecutePrefix(JsonReader instance) throws Throwable {
        try {
            Method method = JsonReader.class.getDeclaredMethod("consumeNonExecutePrefix");
            method.setAccessible(true);
            method.invoke(instance);
        } catch (InvocationTargetException e) {
            throw e.getCause();
        }
    }
}
